<?php
 namespace WPAICG\ContentWriter\Prompt; use WPAICG\ContentWriter\AIPKit_Content_Writer_Prompts; if (!defined('ABSPATH')) { exit; } class AIPKit_Content_Writer_Excerpt_Prompt_Builder { public static function build(string $final_title, string $content_summary, string $keywords, ?string $prompt_mode = 'standard', ?string $custom_excerpt_prompt = null): string { if ($prompt_mode === 'custom' && !empty($custom_excerpt_prompt)) { $prompt_template = $custom_excerpt_prompt; } else { $prompt_template = AIPKit_Content_Writer_Prompts::get_default_excerpt_prompt(); } $prompt = str_replace('{topic}', $final_title, $prompt_template); $prompt = str_replace('{content_summary}', $content_summary, $prompt); $prompt = str_replace('{keywords}', $keywords, $prompt); return $prompt; } } 